+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			result := extractDeltaText([]byte(tt.data), "openai")
+			if result != tt.expected {
+				t.Errorf("extractDeltaText(%q, openai) = %q, want %q", tt.data, result, tt.expected)
+			}
+		})
